noncompliant:
// Noncompliant: #ifndef without matching #define
#ifndef MYHEADER_H
// content
class MyClass {
    // implementation
};
#endif

// Noncompliant: #define doesn't match #ifndef name
#ifndef MYHEADER_H
#define DIFFERENT_NAME
// content
class MyClass {
    // implementation
};
#endif

compliant:
// Compliant: Proper header guard pattern
#ifndef MYHEADER_H
#define MYHEADER_H
// content
class MyClass {
    // implementation
};
#endif

// Alternative compliant approach with #pragma once
#pragma once
// content
class MyClass {
    // implementation
};
